using System;
using System.Collections.Generic;
using System.Linq;

public static class Stats
{
    public static (double Mean, double Max) MeanAndMax(IEnumerable<double> values)
    {
        if (values == null)
        {
            throw new ArgumentNullException(nameof(values), "The sequence cannot be null.");
        }

        bool hasValue = false;
        double sum = 0;
        double max = double.MinValue;
        int count = 0;

        foreach (var value in values)
        {
            if (!hasValue)
            {
                // We found the first value, mark hasValue as true
                hasValue = true;
            }

            sum += value;
            if (value > max)
            {
                max = value;
            }
            count++;
        }

        if (!hasValue)
        {
            throw new ArgumentException("The sequence is empty.", nameof(values));
        }

        return (sum / count, max);
    }
}

