using System;

public static class TextScan
{
    public static int CountWords(ReadOnlySpan<char> text)
    {
        bool inWord = false;
        int wordCount = 0;

        foreach (var ch in text)
        {
            if (char.IsWhiteSpace(ch))
            {
                if (inWord)
                {
                    inWord = false;
                }
            }
            else
            {
                if (!inWord)
                {
                    inWord = true;
                    wordCount++;
                }
            }
        }

        return wordCount;
    }
}

using System;

public static class SpanParser
{
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int sum = 0;
        int start = 0;

        for (int i = 0; i <= csv.Length; i++)
        {
            if (i == csv.Length || csv[i] == ',')
            {
                if (start < i) // Ensure we don't parse empty sections
                {
                    sum += int.Parse(csv.Slice(start, i - start));
                }
                start = i + 1;
            }
        }

        return sum;
    }
}
